import{_ as e,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Visualização Diff: Revisar Alterações de Múltiplos Ângulos | Plannotator","description":"Aprenda a alternar entre tipos de diff no code review do Plannotator. Selecione visualizações uncommitted, staged, last commit ou branch no menu suspenso para revisar alterações de código de múltiploslos ângulos.","frontmatter":{"title":"Visualização Diff: Revisar Alterações de Múltiplos Ângulos | Plannotator","sidebarTitle":"Alternar entre 5 tipos de visualização diff","subtitle":"Visualização Diff: Revisar Alterações de Múltiplos Ângulos","description":"Aprenda a alternar entre tipos de diff no code review do Plannotator. Selecione visualizações uncommitted, staged, last commit ou branch no menu suspenso para revisar alterações de código de múltiploslos ângulos.","tags":["code-review","git","diff","tutorial"],"prerequisite":["code-review-basics"],"order":6},"headers":[],"relativePath":"pt/backnotprop/plannotator/platforms/code-review-diff-types/index.md","filePath":"pt/backnotprop/plannotator/platforms/code-review-diff-types/index.md"}'),i={name:"pt/backnotprop/plannotator/platforms/code-review-diff-types/index.md"};function s(d,a,n,l,c,p){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="alternar-visualizacao-diff" tabindex="-1">Alternar Visualização Diff <a class="header-anchor" href="#alternar-visualizacao-diff" aria-label="Permalink to &quot;Alternar Visualização Diff&quot;">​</a></h1><h2 id="o-que-voce-sera-capaz-de-fazer" tabindex="-1">O Que Você Será Capaz de Fazer <a class="header-anchor" href="#o-que-voce-sera-capaz-de-fazer" aria-label="Permalink to &quot;O Que Você Será Capaz de Fazer&quot;">​</a></h2><p>Ao fazer code review, você poderá:</p><ul><li>Alternar rapidamente entre 5 tipos de visualização diff usando o menu suspenso</li><li>Entender o escopo de alterações de código exibido em cada visualização</li><li>Escolher o tipo de diff apropriado com base nas necessidades de revisão</li><li>Evitar perder alterações importantes por selecionar a visualização errada</li></ul><h2 id="seu-problema-atual" tabindex="-1">Seu Problema Atual <a class="header-anchor" href="#seu-problema-atual" aria-label="Permalink to &quot;Seu Problema Atual&quot;">​</a></h2><p><strong>Ao revisar, você só vê a área de trabalho e perde arquivos já staged</strong>:</p><p>Você executa o comando <code>/plannotator-review</code>, vê algumas alterações de código e adiciona alguns comentários. Mas após o commit, descobre que a revisão perdeu os arquivos que já foram <code>git add</code> para a área de staging—esses arquivos simplesmente não apareceram no diff.</p><p><strong>Quer ver as diferenças gerais entre o branch atual e o branch main</strong>:</p><p>Você está desenvolvendo em um branch feature por algumas semanas e quer ver o que mudou no total, mas a visualização padrão de &quot;alterações não commitadas&quot; só mostra as modificações dos últimos dias.</p><p><strong>Quer comparar as diferenças entre dois commits específicos</strong>:</p><p>Você quer confirmar se uma correção de bug está correta e precisa comparar o código antes e depois da correção, mas não sabe como fazer o Plannotator mostrar o diff de commits históricos.</p><h2 id="quando-usar-esta-tecnica" tabindex="-1">Quando Usar Esta Técnica <a class="header-anchor" href="#quando-usar-esta-tecnica" aria-label="Permalink to &quot;Quando Usar Esta Técnica&quot;">​</a></h2><ul><li><strong>Ao fazer revisão completa</strong>: Verificar alterações da área de trabalho e da área de staging simultaneamente</li><li><strong>Antes de mesclar branches</strong>: Verificar todas as alterações do branch atual em relação a main/master</li><li><strong>Ao revisar rollback</strong>: Confirmar quais arquivos foram alterados no último commit</li><li><strong>Ao colaborar em equipe</strong>: Verificar código que colegas staged mas ainda não commitaram</li></ul><h2 id="ideia-central" tabindex="-1">Ideia Central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia Central&quot;">​</a></h2><p>O comando Git diff tem muitas variantes, cada uma exibindo um escopo diferente de código. O Plannotator centraliza essas variantes em um menu suspenso, para que você não precise memorizar comandos git complexos.</p><div class="info custom-block"><p class="custom-block-title">Referência Rápida de Tipos de Diff Git</p><table tabindex="0"><thead><tr><th>Tipo de diff</th><th>Escopo exibido</th><th>Cenário típico de uso</th></tr></thead><tbody><tr><td>Uncommitted changes</td><td>Área de trabalho + Área de staging</td><td>Revisar todas as modificações deste desenvolvimento</td></tr><tr><td>Staged changes</td><td>Apenas área de staging</td><td>Revisar conteúdo preparado para commit antes de commitar</td></tr><tr><td>Unstaged changes</td><td>Apenas área de trabalho</td><td>Revisar modificações ainda não <code>git add</code></td></tr><tr><td>Last commit</td><td>Commit mais recente</td><td>Revisar commit anterior ou fazer rollback</td></tr><tr><td>vs main</td><td>Branch atual vs branch padrão</td><td>Verificação completa antes de mesclar branch</td></tr></tbody></table></div><p>As opções do menu suspenso mudam dinamicamente com base no seu estado Git:</p><ul><li>Se você não está no branch padrão, a opção &quot;vs main&quot; será exibida</li><li>Se não houver arquivos staged, a visualização Staged mostrará &quot;No staged changes&quot;</li></ul><h2 id="siga-os-passos" tabindex="-1">Siga os Passos <a class="header-anchor" href="#siga-os-passos" aria-label="Permalink to &quot;Siga os Passos&quot;">​</a></h2><h3 id="passo-1-iniciar-code-review" tabindex="-1">Passo 1: Iniciar Code Review <a class="header-anchor" href="#passo-1-iniciar-code-review" aria-label="Permalink to &quot;Passo 1: Iniciar Code Review&quot;">​</a></h3><p><strong>Por que</strong></p><p>É necessário abrir primeiro a interface de code review do Plannotator.</p><p><strong>Operação</strong></p><p>Execute no terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>O que você deve ver</strong></p><p>O navegador abriu a página de code review, acima da árvore de arquivos à esquerda há um menu suspenso mostrando o tipo de diff atual (geralmente &quot;Uncommitted changes&quot;).</p><h3 id="passo-2-alternar-para-visualizacao-staged" tabindex="-1">Passo 2: Alternar para Visualização Staged <a class="header-anchor" href="#passo-2-alternar-para-visualizacao-staged" aria-label="Permalink to &quot;Passo 2: Alternar para Visualização Staged&quot;">​</a></h3><p><strong>Por que</strong></p><p>Ver arquivos que já foram <code>git add</code> mas ainda não foram commitados.</p><p><strong>Operação</strong></p><ol><li>Clique no menu suspenso acima da árvore de arquivos à esquerda</li><li>Selecione &quot;Staged changes&quot;</li></ol><p><strong>O que você deve ver</strong></p><ul><li>Se houver arquivos staged, a árvore de arquivos mostrará esses arquivos</li><li>Se não houver arquivos staged, a área principal mostrará: &quot;No staged changes. Stage some files with git add.&quot;</li></ul><h3 id="passo-3-alternar-para-visualizacao-last-commit" tabindex="-1">Passo 3: Alternar para Visualização Last Commit <a class="header-anchor" href="#passo-3-alternar-para-visualizacao-last-commit" aria-label="Permalink to &quot;Passo 3: Alternar para Visualização Last Commit&quot;">​</a></h3><p><strong>Por que</strong></p><p>Revisar o código que acabou de ser commitado, confirmando que não há problemas.</p><p><strong>Operação</strong></p><ol><li>Abra o menu suspenso novamente</li><li>Selecione &quot;Last commit&quot;</li></ol><p><strong>O que você deve ver</strong></p><ul><li>Exibe todos os arquivos modificados no commit mais recente</li><li>O conteúdo do diff é a diferença entre <code>HEAD~1..HEAD</code></li></ul><h3 id="passo-4-alternar-para-visualizacao-vs-main-se-disponivel" tabindex="-1">Passo 4: Alternar para Visualização vs main (se disponível) <a class="header-anchor" href="#passo-4-alternar-para-visualizacao-vs-main-se-disponivel" aria-label="Permalink to &quot;Passo 4: Alternar para Visualização vs main (se disponível)&quot;">​</a></h3><p><strong>Por que</strong></p><p>Ver todas as alterações do branch atual em relação ao branch padrão.</p><p><strong>Operação</strong></p><ol><li>Verifique se há uma opção &quot;vs main&quot; ou &quot;vs master&quot; no menu suspenso</li><li>Se houver, selecione-a</li></ol><p><strong>O que você deve ver</strong></p><ul><li>A árvore de arquivos mostra todos os arquivos diferentes entre o branch atual e o branch padrão</li><li>O conteúdo do diff são as alterações completas de <code>main..HEAD</code></li></ul><div class="tip custom-block"><p class="custom-block-title">Verificar Branch Atual</p><p>Se você não vir a opção &quot;vs main&quot;, significa que está no branch padrão. Você pode usar o seguinte comando para ver o branch atual:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abbrev-ref</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD</span></span></code></pre></div><p>Tente novamente após alternar para um branch feature:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div></div><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de Verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de Verificação ✅&quot;">​</a></h2><p>Confirme que você dominou:</p><ul><li>[ ] Consegue encontrar e abrir o menu suspenso de tipos de diff</li><li>[ ] Entende a diferença entre &quot;Uncommitted&quot;, &quot;Staged&quot; e &quot;Last commit&quot;</li><li>[ ] Consegue identificar quando a opção &quot;vs main&quot; aparece</li><li>[ ] Sabe qual tipo de diff usar em qual cenário</li></ul><h2 id="cuidado-com-armadilhas" tabindex="-1">Cuidado com Armadilhas <a class="header-anchor" href="#cuidado-com-armadilhas" aria-label="Permalink to &quot;Cuidado com Armadilhas&quot;">​</a></h2><h3 id="armadilha-1-ao-revisar-so-ve-uncommitted-e-perde-arquivos-staged" tabindex="-1">Armadilha 1: Ao revisar, só vê Uncommitted e perde arquivos Staged <a class="header-anchor" href="#armadilha-1-ao-revisar-so-ve-uncommitted-e-perde-arquivos-staged" aria-label="Permalink to &quot;Armadilha 1: Ao revisar, só vê Uncommitted e perde arquivos Staged&quot;">​</a></h3><p><strong>Sintoma</strong></p><p>Após o commit, descobre que a revisão perdeu alguns arquivos já staged.</p><p><strong>Causa</strong></p><p>A visualização Uncommitted mostra todas as alterações da área de trabalho e da área de staging (<code>git diff HEAD</code>), então arquivos já staged também serão incluídos.</p><p><strong>Solução</strong></p><p>Antes da revisão, alterne para a visualização Staged para verificar uma vez, ou use a visualização Uncommitted (que inclui a área de staging).</p><h3 id="armadilha-2-nao-comparou-com-main-antes-de-mesclar-branch" tabindex="-1">Armadilha 2: Não comparou com main antes de mesclar branch <a class="header-anchor" href="#armadilha-2-nao-comparou-com-main-antes-de-mesclar-branch" aria-label="Permalink to &quot;Armadilha 2: Não comparou com main antes de mesclar branch&quot;">​</a></h3><p><strong>Sintoma</strong></p><p>Após mesclar com main, descobre que introduziu modificações não relacionadas.</p><p><strong>Causa</strong></p><p>Só viu os commits dos últimos dias, não comparou a diferença do branch inteiro em relação a main.</p><p><strong>Solução</strong></p><p>Antes de mesclar, faça a verificação completa usando a visualização &quot;vs main&quot;.</p><h3 id="armadilha-3-acha-que-alternar-visualizacao-perde-comentarios" tabindex="-1">Armadilha 3: Acha que alternar visualização perde comentários <a class="header-anchor" href="#armadilha-3-acha-que-alternar-visualizacao-perde-comentarios" aria-label="Permalink to &quot;Armadilha 3: Acha que alternar visualização perde comentários&quot;">​</a></h3><p><strong>Sintoma</strong></p><p>Não ousa alternar o tipo de diff, preocupado que os comentários adicionados anteriormente desapareçam.</p><p><strong>Causa</strong></p><p>Mal-entendido do mecanismo de alternância.</p><p><strong>Situação Real</strong></p><p>Ao alternar o tipo de diff, o Plannotator preserva os comentários anteriores—eles ainda podem ser aplicáveis, ou você pode excluir manualmente comentários não relacionados.</p><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><p>Os 5 tipos de diff suportados pelo Plannotator:</p><table tabindex="0"><thead><tr><th>Tipo</th><th>Comando Git</th><th>Cenário</th></tr></thead><tbody><tr><td>Uncommitted</td><td><code>git diff HEAD</code></td><td>Revisar todas as modificações deste desenvolvimento</td></tr><tr><td>Staged</td><td><code>git diff --staged</code></td><td>Revisar área de staging antes de commitar</td></tr><tr><td>Unstaged</td><td><code>git diff</code></td><td>Revisar modificações da área de trabalho</td></tr><tr><td>Last commit</td><td><code>git diff HEAD~1..HEAD</code></td><td>Fazer rollback ou revisar commit recente</td></tr><tr><td>vs main</td><td><code>git diff main..HEAD</code></td><td>Verificação completa antes de mesclar branch</td></tr></tbody></table><p>Alternar visualizações não perde comentários, você pode ver o mesmo lote ou novos comentários de diferentes perspectivas.</p><h2 id="proxima-licao" tabindex="-1">Próxima Lição <a class="header-anchor" href="#proxima-licao" aria-label="Permalink to &quot;Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos <strong><a href="./../../advanced/url-sharing/">Compartilhamento de URL</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como compactar o conteúdo de revisão em uma URL para compartilhar com colegas</li><li>Como o destinatário abre o link de revisão compartilhado</li><li>Limitações e considerações no modo de compartilhamento</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código-Fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código-Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver localização do código-fonte</strong></summary><blockquote><p>Última atualização: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Número da linha</th></tr></thead><tbody><tr><td>Definição de tipos de Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L10-L15" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>10-15</td></tr><tr><td>Obtenção de contexto Git</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L79-L96" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>79-96</td></tr><tr><td>Execução de Git Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L101-L147" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>101-147</td></tr><tr><td>Tratamento de alternância de Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L300-L331" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>300-331</td></tr><tr><td>Renderização de opções Diff na árvore de arquivos</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/components/FileTree.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/components/FileTree.tsx</code></a></td><td>-</td></tr></tbody></table><p><strong>Tipos principais</strong>:</p><ul><li><code>DiffType</code>: <code>&#39;uncommitted&#39; | &#39;staged&#39; | &#39;unstaged&#39; | &#39;last-commit&#39; | &#39;branch&#39;</code></li></ul><p><strong>Funções principais</strong>:</p><ul><li><code>getGitContext()</code>: Obtém branch atual, branch padrão e opções de diff disponíveis</li><li><code>runGitDiff(diffType, defaultBranch)</code>: Executa o comando git correspondente com base no tipo de diff</li></ul><p><strong>APIs principais</strong>:</p><ul><li><code>POST /api/diff/switch</code>: Alterna tipo de diff, retorna novos dados de diff</li></ul></details>',83)])])}const h=e(i,[["render",s]]);export{m as __pageData,h as default};
